/**
 * @summary List purchased subdomains for a storeid
 */
export const getListPurchasedSubdomainsUrl = (
  params: ListPurchasedSubdomainsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/subdomains?${stringifiedParams}`
    : `/api/subdomains`;
};

export const listPurchasedSubdomains = async (
  params: ListPurchasedSubdomainsParams,
  options?: RequestInit,
): Promise<PurchasedSubdomain[]> => {
  return customFetch<PurchasedSubdomain[]>(
    getListPurchasedSubdomainsUrl(params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getListPurchasedSubdomainsQueryKey = (
  params?: ListPurchasedSubdomainsParams,
) => {
  return [`/api/subdomains`, ...(params ? [params] : [])] as const;
};

export const getListPurchasedSubdomainsQueryOptions = <
  TData = Awaited<ReturnType<typeof listPurchasedSubdomains>>,
  TError = ErrorType<unknown>,
>(
  params: ListPurchasedSubdomainsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listPurchasedSubdomains>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListPurchasedSubdomainsQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof listPurchasedSubdomains>>
  > = ({ signal }) =>
    listPurchasedSubdomains(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listPurchasedSubdomains>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

